    }
    return c
  })

const computePropDefault = ({ default: def, type }) => {
  // Default could be a function that returns a non-primitive type
  def = typeof def === 'function' ? def.call({}) : def
  if (type === Boolean || (Array.isArray(type) && type[0] === Boolean && !def)) {
    def = Boolean(def)
  } else if (def === undefined) {
    def = null
  }
  return JSON.stringify(def)
}

const parseHMS = value => {
  value = toString(value)
  let [hh, mm, ss] = [null, null, null]
  if (RX_TIME.test(value)) {
    ;[hh, mm, ss] = value.split(':').map(v => toInteger(v, null))
  }
  return {
    hours: isUndefinedOrNull(hh) ? null : hh,
    minutes: isUndefinedOrNull(mm) ? null : mm,
    seconds: isUndefinedOrNull(ss) ? null : ss,
    ampm: isUndefinedOrNull(hh) || hh < 12 ? 0 : 1
  }
}

export const setConfig = (config = {}, Vue = OurVue) => {
  // Ensure we have a `$bvConfig` Object on the Vue prototype
  // We set on Vue and OurVue just in case consumer has not set an alias of `vue`
  Vue.prototype[PROP_NAME] = OurVue.prototype[PROP_NAME] =
    Vue.prototype[PROP_NAME] || OurVue.prototype[PROP_NAME] || new BvConfig()
  // Apply the config values
  Vue.prototype[PROP_NAME].setConfig(config)
}

export const offset = el => /* istanbul ignore next: getBoundingClientRect(), getClientRects() doesn't work in JSDOM */ {
  const _offset = { top: 0, left: 0 }
  if (!isElement(el) || el.getClientRects().length === 0) {
    return _offset
  }
  const bcr = getBCR(el)
  if (bcr) {
    const win = el.ownerDocument.defaultView
    _offset.top = bcr.top + win.pageYOffset
    _offset.left = bcr.left + win.pageXOffset
  }
  return _offset
}

const clicked = (e: Readonly<MouseEvent>): void => {
  if (props.disabled) {
    e.preventDefault()
    e.stopImmediatePropagation()
    return
  }

  if (
    (collapseData?.isNav?.value === true && navbarData === null) ||
    (navbarData !== null && navbarData.noAutoClose?.value !== true)
  ) {
    collapseData?.hide?.()
  }

  emit('click', e)
}

const keynav = (e: Event, direction: number) => {
  if (tabs.value.length <= 0 || props.noKeyNav) return
  e.preventDefault()
  e.stopPropagation()
  activeIndex.value = nextIndex(activeIndex.value + direction, direction)
  nextTick(() => {
    if (activeIndex.value >= 0) {
      getSafeDocument()?.getElementById(tabs.value[activeIndex.value]?.buttonId)?.focus()
    }
  })
}

export type BDateRangePickerSlots = {
  'field'?: (props: {
    segments: {
      start: {part: SegmentPart; value: string}[]
      end: {part: SegmentPart; value: string}[]
    }
  }) => any
  'calendar'?: (props: {weekDays: string[]; grid: any[]}) => any
  'trigger-icon'?: (props: Record<string, never>) => any
  'prev-icon'?: (props: Record<string, never>) => any
  'next-icon'?: (props: Record<string, never>) => any
}

export const getSlotElements = (slot: Slot | undefined, filterBy: string): VNode[] =>
  (slot?.() ?? [])
    .reduce((arr: VNode[], slot: VNode) => {
      if (typeof slot.type === 'symbol') {
        arr = arr.concat(slot.children as unknown as VNode)
      } else {
        arr.push(slot)
      }
      return arr
    }, [])
    .filter((child) => (child.type as {__name: string} | undefined)?.__name === filterBy)

